"""Voronoi-based circle packing using Lloyd iteration and SLSQP refinement"""
import numpy as np
from scipy.spatial import Voronoi
from scipy.optimize import minimize

def construct_packing():
    """Use Voronoi diagram for iterative territory-based optimization.

    1. Start with hexagonal initial positions
    2. Apply Lloyd's algorithm: compute Voronoi diagram, move centers to cell centroids
    3. Refine with SLSQP optimization for final positions and radii
    """
    n = 26

    def get_initial_positions():
        """Generate hexagonal initial positions."""
        centers = np.zeros((n, 2))
        r = 0.095
        row_counts = [5, 4, 5, 4, 5, 3]
        y_spacing = r * np.sqrt(3)
        idx = 0
        for row, count in enumerate(row_counts):
            y = r + row * y_spacing
            if count == 5:
                x_positions = [r + i * 2 * r for i in range(5)]
            elif count == 4:
                x_positions = [2 * r + i * 2 * r for i in range(4)]
            else:
                x_positions = [r + i * 2 * r for i in range(3)]
            for x in x_positions:
                centers[idx] = [x, y]
                idx += 1
        return centers

    def lloyd_iteration(centers, max_iter=25):
        """Apply Lloyd's algorithm using Voronoi diagram."""
        for _ in range(max_iter):
            # Add mirror points for boundary handling
            mirrors = []
            for c in centers:
                mirrors.extend([
                    [-c[0], c[1]], [2-c[0], c[1]],
                    [c[0], -c[1]], [c[0], 2-c[1]],
                ])
            all_points = np.vstack([centers, np.array(mirrors)])
            vor = Voronoi(all_points)

            new_centers = np.zeros_like(centers)
            for i in range(n):
                region = vor.regions[vor.point_region[i]]
                if -1 in region or len(region) < 3:
                    new_centers[i] = centers[i]
                else:
                    vertices = np.clip(vor.vertices[region], 0.01, 0.99)
                    centroid = np.mean(vertices, axis=0)
                    new_centers[i] = np.clip(centroid, 0.01, 0.99)

            if np.max(np.abs(new_centers - centers)) < 1e-7:
                break
            centers = new_centers
        return centers

    def compute_initial_radii(centers):
        """Compute initial radii from constraints."""
        radii = np.array([min(x, y, 1-x, 1-y) for x, y in centers])
        return np.maximum(radii, 0.01)

    def pack_vars(centers, radii):
        x = np.zeros(3 * n)
        for i in range(n):
            x[3*i], x[3*i+1], x[3*i+2] = centers[i, 0], centers[i, 1], radii[i]
        return x

    def unpack_vars(x):
        centers = np.hstack([x[0::3].reshape(n, 1), x[1::3].reshape(n, 1)])
        return centers, x[2::3].copy()

    def objective(x):
        return -np.sum(x[2::3])

    # Build constraints
    constraints = []
    for i in range(n):
        constraints.append({'type': 'ineq', 'fun': lambda x, i=i: x[3*i] - x[3*i+2]})
        constraints.append({'type': 'ineq', 'fun': lambda x, i=i: 1 - x[3*i] - x[3*i+2]})
        constraints.append({'type': 'ineq', 'fun': lambda x, i=i: x[3*i+1] - x[3*i+2]})
        constraints.append({'type': 'ineq', 'fun': lambda x, i=i: 1 - x[3*i+1] - x[3*i+2]})

    for i in range(n):
        for j in range(i+1, n):
            constraints.append({
                'type': 'ineq',
                'fun': lambda x, i=i, j=j: np.sqrt((x[3*i]-x[3*j])**2 + (x[3*i+1]-x[3*j+1])**2) - x[3*i+2] - x[3*j+2]
            })

    bounds = []
    for i in range(n):
        bounds.extend([(0.01, 0.99), (0.01, 0.99), (0.01, 0.5)])

    # Initialize with Voronoi-optimized positions
    centers = get_initial_positions()
    centers = lloyd_iteration(centers)
    radii = compute_initial_radii(centers)

    best_sum, best_solution = 0, None

    # Multiple restarts with Voronoi-refined initial positions
    for restart in range(8):
        if restart > 0:
            # Perturb positions for diversity
            np.random.seed(42 + restart * 17)
            centers_perturbed = centers + np.random.uniform(-0.03, 0.03, centers.shape)
            centers_perturbed = np.clip(centers_perturbed, 0.05, 0.95)
            radii_init = compute_initial_radii(centers_perturbed)
        else:
            centers_perturbed = centers.copy()
            radii_init = radii.copy()

        x0 = pack_vars(centers_perturbed, radii_init)

        result = minimize(
            objective, x0, method='SLSQP',
            bounds=bounds, constraints=constraints,
            options={'maxiter': 2000, 'ftol': 1e-9, 'disp': False}
        )

        centers_opt, radii_opt = unpack_vars(result.x)
        radii_opt = np.maximum(radii_opt, 0.01)
        current_sum = np.sum(radii_opt)

        if current_sum > best_sum:
            best_sum = current_sum
            best_solution = (centers_opt.copy(), radii_opt.copy())

    centers, radii = best_solution
    return centers, radii, np.sum(radii)
